ALTER TABLE public.email_settings
ADD COLUMN IF NOT EXISTS invoice_subject TEXT,
ADD COLUMN IF NOT EXISTS invoice_template TEXT;

UPDATE public.email_settings
SET
  invoice_subject = COALESCE(
    invoice_subject,
    'Faktura {{invoice_number}} od {{company_name}}'
  ),
  invoice_template = COALESCE(
    invoice_template,
    '<!DOCTYPE html><html lang="pl"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Faktura {{invoice_number}}</title></head><body style="margin:0;padding:0;background:#f6f5ff;font-family:Segoe UI,Arial,sans-serif;color:#1f2937;"><table role="presentation" style="width:100%;border-collapse:collapse;"><tr><td style="padding:24px;"><table role="presentation" style="max-width:640px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;border:1px solid #ebe8ff;"><tr><td style="padding:28px 32px;background:linear-gradient(135deg,#6d4aff 0%,#8f6bff 100%);color:#ffffff;"><p style="margin:0 0 8px;font-size:12px;letter-spacing:.08em;text-transform:uppercase;opacity:.9;">GetRido • wysyłka faktury</p><h1 style="margin:0;font-size:28px;line-height:1.2;">Faktura {{invoice_number}}</h1><p style="margin:10px 0 0;font-size:15px;opacity:.95;">Wiadomość od {{company_name}}</p></td></tr><tr><td style="padding:28px 32px;"><p style="margin:0 0 14px;font-size:15px;line-height:1.7;">Dzień dobry,</p><p style="margin:0 0 18px;font-size:15px;line-height:1.7;">w załączniku przesyłamy fakturę <strong>{{invoice_number}}</strong> wystawioną przez <strong>{{company_name}}</strong> dla <strong>{{buyer_name}}</strong>.</p><table role="presentation" style="width:100%;border-collapse:collapse;background:#f8f7ff;border:1px solid #ebe8ff;border-radius:14px;"><tr><td style="padding:18px 20px;"><table role="presentation" style="width:100%;border-collapse:collapse;"><tr><td style="padding:6px 0;color:#6b7280;font-size:13px;">Data wystawienia</td><td style="padding:6px 0;text-align:right;font-size:14px;font-weight:600;">{{issue_date}}</td></tr><tr><td style="padding:6px 0;color:#6b7280;font-size:13px;">Termin płatności</td><td style="padding:6px 0;text-align:right;font-size:14px;font-weight:700;color:#6d4aff;">{{due_date}}</td></tr><tr><td style="padding:6px 0;color:#6b7280;font-size:13px;">Kwota netto</td><td style="padding:6px 0;text-align:right;font-size:14px;font-weight:600;">{{net_amount}} {{currency}}</td></tr><tr><td style="padding:6px 0;color:#6b7280;font-size:13px;">Kwota brutto</td><td style="padding:6px 0;text-align:right;font-size:18px;font-weight:800;color:#6d4aff;">{{gross_amount}} {{currency}}</td></tr></table></td></tr></table><div style="margin-top:20px;padding:18px 20px;border:1px solid #ebe8ff;border-radius:14px;"><p style="margin:0 0 10px;font-size:13px;color:#6b7280;text-transform:uppercase;letter-spacing:.06em;">Dane wystawcy</p><p style="margin:0 0 4px;font-size:16px;font-weight:700;">{{company_name}}</p><p style="margin:0 0 4px;font-size:14px;color:#4b5563;">NIP: {{company_nip}}</p><p style="margin:0 0 4px;font-size:14px;color:#4b5563;">{{company_address}}</p><p style="margin:0 0 4px;font-size:14px;color:#4b5563;">{{company_email}}</p><p style="margin:0;font-size:14px;color:#4b5563;">{{company_phone}}</p></div><div style="margin-top:20px;padding:18px 20px;background:#f9fafb;border-radius:14px;"><p style="margin:0 0 8px;font-size:13px;color:#6b7280;text-transform:uppercase;letter-spacing:.06em;">Dane do płatności</p><p style="margin:0 0 4px;font-size:14px;color:#374151;">Bank: <strong>{{company_bank_name}}</strong></p><p style="margin:0;font-size:14px;color:#374151;">Konto: <strong>{{company_bank_account}}</strong></p></div><p style="margin:20px 0 0;font-size:14px;line-height:1.7;color:#4b5563;">Faktura PDF została dodana w załączniku tej wiadomości.</p></td></tr><tr><td style="padding:18px 32px;background:#fafafe;border-top:1px solid #ebe8ff;"><p style="margin:0;font-size:12px;line-height:1.6;color:#6b7280;">Wiadomość została wysłana przez portal GetRido w imieniu firmy {{company_name}}.</p></td></tr></table></td></tr></table></body></html>'
  ),
  updated_at = NOW()
WHERE id = '00000000-0000-0000-0000-000000000001';